#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <cuda_runtime.h>

#include "./main.h"

#include "./util/graphics/graphics.h"
#include "./util/graphics/resize.h"
#include "./util/timer/timer.h"

#include "./kernel/kernel_gpu_cuda_wrapper.h"

void check_cuda_error(cudaError_t error, int line_no) {
    if (error != cudaSuccess) {
        fprintf(stderr, "CUDA Error at line %d: %s\n", line_no, cudaGetErrorString(error));
        exit(1);
    }
}

void 
kernel_gpu_cuda_wrapper(	fp* image,											
							int Nr,												
							int Nc,												
							long Ne,											
							int niter,											
							fp lambda,											
							long NeROI,											
							int* iN,
							int* iS,
							int* jE,
							int* jW,
							int iter,											
							int mem_size_i,
							int mem_size_j)
{

#ifdef TIMING
    struct timeval tv;
    struct timeval tv_total_start, tv_total_end;
    struct timeval tv_init_end;
    struct timeval tv_h2d_start, tv_h2d_end;
    struct timeval tv_d2h_start, tv_d2h_end;
    struct timeval tv_kernel_start, tv_kernel_end;
    struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
    struct timeval tv_close_start, tv_close_end;
    float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time = 0,
                d2h_time = 0, close_time = 0, total_time = 0;

    gettimeofday(&tv_total_start, NULL);
#endif

	cudaError_t error;

#ifdef  TIMING
    gettimeofday(&tv_init_end, NULL);
    tvsub(&tv_init_end, &tv_total_start, &tv);
    init_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

	int blocks_x;

	int mem_size;															
	mem_size = sizeof(fp) * Ne;												

	fp* d_I;
	error = cudaMalloc(&d_I, mem_size);
	check_cuda_error(error, __LINE__);

	int* d_iN;
	error = cudaMalloc(&d_iN, mem_size_i);
	check_cuda_error(error, __LINE__);

	int* d_iS;
	error = cudaMalloc(&d_iS, mem_size_i);
	check_cuda_error(error, __LINE__);

	int* d_jE;
	error = cudaMalloc(&d_jE, mem_size_j);
	check_cuda_error(error, __LINE__);

	int* d_jW;
	error = cudaMalloc(&d_jW, mem_size_j);
	check_cuda_error(error, __LINE__);

	fp* d_dN;
	error = cudaMalloc(&d_dN, mem_size);
	check_cuda_error(error, __LINE__);

	fp* d_dS;
	error = cudaMalloc(&d_dS, mem_size);
	check_cuda_error(error, __LINE__);

	fp* d_dW;
	error = cudaMalloc(&d_dW, mem_size);
	check_cuda_error(error, __LINE__);

	fp* d_dE;
	error = cudaMalloc(&d_dE, mem_size);
	check_cuda_error(error, __LINE__);

	fp* d_c;
	error = cudaMalloc(&d_c, mem_size);
	check_cuda_error(error, __LINE__);

	fp* d_sums;
	error = cudaMalloc(&d_sums, mem_size);
	check_cuda_error(error, __LINE__);

	fp* d_sums2;
	error = cudaMalloc(&d_sums2, mem_size);
	check_cuda_error(error, __LINE__);

#ifdef  TIMING
  gettimeofday(&tv_mem_alloc_end, NULL);
  tvsub(&tv_mem_alloc_end, &tv_init_end, &tv);
  mem_alloc_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

	error = cudaMemcpy(d_I, image, mem_size, cudaMemcpyHostToDevice);
	check_cuda_error(error, __LINE__);

	error = cudaMemcpy(d_iN, iN, mem_size_i, cudaMemcpyHostToDevice);
	check_cuda_error(error, __LINE__);

	error = cudaMemcpy(d_iS, iS, mem_size_i, cudaMemcpyHostToDevice);
	check_cuda_error(error, __LINE__);

	error = cudaMemcpy(d_jE, jE, mem_size_j, cudaMemcpyHostToDevice);
	check_cuda_error(error, __LINE__);

	error = cudaMemcpy(d_jW, jW, mem_size_j, cudaMemcpyHostToDevice);
	check_cuda_error(error, __LINE__);

	size_t local_work_size = NUMBER_THREADS;

	int blocks_work_size;
	size_t global_work_size;
	blocks_x = Ne/(int)local_work_size;
	if (Ne % (int)local_work_size != 0){												
		blocks_x = blocks_x + 1;																	
	}
	blocks_work_size = blocks_x;
	global_work_size = blocks_work_size * local_work_size;						

	printf("max # of workgroups = %d, # of threads/workgroup = %d (ensure that device can handle)\n", (int)(global_work_size/local_work_size), (int)local_work_size);

	dim3 block_dim(local_work_size);
	dim3 grid_dim(blocks_work_size);

	extract_kernel(grid_dim, block_dim, Ne, d_I);
	error = cudaGetLastError();
	check_cuda_error(error, __LINE__);

#ifdef TIMING
    kernel_time += 0; // Simplified for this translation
#endif

	prepare_kernel(grid_dim, block_dim, Ne, d_I, d_sums, d_sums2);
	error = cudaGetLastError();
	check_cuda_error(error, __LINE__);

	int blocks2_x;
	int blocks2_work_size;
	size_t global_work_size2;
	long no;
	int mul;
	int mem_size_single = sizeof(fp) * 1;
	fp total;
	fp total2;
	fp meanROI;
	fp meanROI2;
	fp varROI;
	fp q0sqr;

	error = cudaGetLastError();
	check_cuda_error(error, __LINE__);

	printf("Iterations Progress: hidden");

	for (iter=0; iter<niter; iter++){										


		fflush(NULL);

		prepare_kernel(grid_dim, block_dim, Ne, d_I, d_sums, d_sums2);
		error = cudaGetLastError();
		check_cuda_error(error, __LINE__);

		blocks2_work_size = blocks_work_size;							
		global_work_size2 = global_work_size;
		no = Ne;														
		mul = 1;														

		while(blocks2_work_size != 0){

			dim3 grid_dim2(blocks2_work_size);

			reduce_kernel(grid_dim2, block_dim, Ne, no, mul, d_sums, d_sums2, blocks2_work_size);
			error = cudaGetLastError();
			check_cuda_error(error, __LINE__);

			no = blocks2_work_size;												
			if(blocks2_work_size == 1){
				blocks2_work_size = 0;
			}
			else{
				mul = mul * NUMBER_THREADS;										
				blocks_x = blocks2_work_size/(int)local_work_size;			
				if (blocks2_work_size % (int)local_work_size != 0){			
					blocks_x = blocks_x + 1;
				}
				blocks2_work_size = blocks_x;
				global_work_size2 = blocks2_work_size * (int)local_work_size;
			}

		}

		error = cudaMemcpy(&total, d_sums, mem_size_single, cudaMemcpyDeviceToHost);
		check_cuda_error(error, __LINE__);

		error = cudaMemcpy(&total2, d_sums2, mem_size_single, cudaMemcpyDeviceToHost);
		check_cuda_error(error, __LINE__);

		meanROI	= total / (fp)(NeROI);										
		meanROI2 = meanROI * meanROI;										
		varROI = (total2 / (fp)(NeROI)) - meanROI2;							
		q0sqr = varROI / meanROI2;											

		srad_kernel(grid_dim, block_dim, lambda, Nr, Nc, Ne, d_iN, d_iS, d_jE, d_jW, d_dN, d_dS, d_dW, d_dE, q0sqr, d_c, d_I);
		error = cudaGetLastError();
		check_cuda_error(error, __LINE__);

		srad2_kernel(grid_dim, block_dim, lambda, Nr, Nc, Ne, d_iN, d_iS, d_jE, d_jW, d_dN, d_dS, d_dW, d_dE, d_c, d_I);
		error = cudaGetLastError();
		check_cuda_error(error, __LINE__);

	}

	printf("\n");

	compress_kernel(grid_dim, block_dim, Ne, d_I);
	error = cudaGetLastError();
	check_cuda_error(error, __LINE__);

	error = cudaDeviceSynchronize();
	check_cuda_error(error, __LINE__);

	error = cudaMemcpy(image, d_I, mem_size, cudaMemcpyDeviceToHost);
	check_cuda_error(error, __LINE__);

#ifdef  TIMING
    gettimeofday(&tv_close_start, NULL);
#endif

	error = cudaFree(d_I);
	check_cuda_error(error, __LINE__);
	error = cudaFree(d_c);
	check_cuda_error(error, __LINE__);

	error = cudaFree(d_iN);
	check_cuda_error(error, __LINE__);
	error = cudaFree(d_iS);
	check_cuda_error(error, __LINE__);
	error = cudaFree(d_jE);
	check_cuda_error(error, __LINE__);
	error = cudaFree(d_jW);
	check_cuda_error(error, __LINE__);

	error = cudaFree(d_dN);
	check_cuda_error(error, __LINE__);
	error = cudaFree(d_dS);
	check_cuda_error(error, __LINE__);
	error = cudaFree(d_dE);
	check_cuda_error(error, __LINE__);
	error = cudaFree(d_dW);
	check_cuda_error(error, __LINE__);

	error = cudaFree(d_sums);
	check_cuda_error(error, __LINE__);
	error = cudaFree(d_sums2);
	check_cuda_error(error, __LINE__);

#ifdef  TIMING
	printf("Time spent in different stages of the application:\n");
    gettimeofday(&tv_close_end, NULL);
    tvsub(&tv_close_end, &tv_close_start, &tv);
    close_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
    tvsub(&tv_close_end, &tv_total_start, &tv);
    total_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;

    printf("Init: %f\n", init_time);
    printf("MemAlloc: %f\n", mem_alloc_time);
    printf("HtoD: %f\n", h2d_time);
    printf("Exec: %f\n", kernel_time);
    printf("DtoH: %f\n", d2h_time);
    printf("Close: %f\n", close_time);
    printf("Total: %f\n", total_time);
#endif
}
